// Generates src/yivi/yivi-css-text.ts containing the Yivi CSS as a string constant.
// Run as a prebuild step: node scripts/generate-yivi-css.mjs

import { readFileSync, writeFileSync } from 'fs';

const cssPath = 'node_modules/@privacybydesign/yivi-css/dist/yivi.css';
const raw = readFileSync(cssPath, 'utf-8');
// Strip source map comment to avoid build warnings
const css = raw.replace(/\/\*#\s*sourceMappingURL=.*?\*\/\s*$/, '').trimEnd();

// Escape backticks and ${} template expressions
const escaped = css.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');

const output = `// Auto-generated by scripts/generate-yivi-css.mjs — do not edit
export const YIVI_CSS = \`${escaped}\`;
`;

writeFileSync('src/yivi/yivi-css-text.ts', output);
console.log(`Generated yivi-css-text.ts (${(css.length / 1024).toFixed(1)} KB)`);
